CREATE TABLE IF NOT EXISTS ota_credentials (
 id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, tenant_id BIGINT UNSIGNED NOT NULL, system_hotel_id BIGINT UNSIGNED NOT NULL, platform VARCHAR(20) NOT NULL, config_id VARCHAR(100) NOT NULL, encrypted_payload LONGTEXT NOT NULL, payload_version INT NOT NULL DEFAULT 1, key_id VARCHAR(100) NOT NULL, secret_mask VARCHAR(255) NOT NULL DEFAULT '', credential_status VARCHAR(20) NOT NULL DEFAULT 'ready', created_by BIGINT UNSIGNED NOT NULL, rotated_at DATETIME NULL, create_time DATETIME NULL, update_time DATETIME NULL, UNIQUE KEY uq_ota_credential_scope(tenant_id,system_hotel_id,platform,config_id), KEY idx_ota_credential_tenant_hotel_status(tenant_id,system_hotel_id,credential_status)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
